import{_ as a,o as e,c as r,ag as d}from"./chunks/framework.WmBmIPw-.js";const p=JSON.parse('{"title":"元启发式（Metaheuristics）","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/metaheuristics.md","filePath":"or-opt/metaheuristics.md","lastUpdated":1777186097000}'),i={name:"or-opt/metaheuristics.md"};function s(h,t,o,l,n,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="元启发式-metaheuristics" tabindex="-1">元启发式（Metaheuristics） <a class="header-anchor" href="#元启发式-metaheuristics" aria-label="Permalink to &quot;元启发式（Metaheuristics）&quot;">​</a></h1><p>元启发式是在编码解表示上，用通用高层迭代机制在探索与利用间平衡的启发式类方法。分类与三类边界见 <a href="./heuristic-algorithms.html">启发式算法总览</a>。与总览中「后主体循环」的体例一致，本目录下各篇在展开记号、机制等正文后、在给出主循环框之前，会写清调参/实现要点（个别篇含内层子过程小框，见各文相应小节）。</p><h2 id="篇目" tabindex="-1">篇目 <a class="header-anchor" href="#篇目" aria-label="Permalink to &quot;篇目&quot;">​</a></h2><table tabindex="0"><thead><tr><th>算法</th><th>说明</th></tr></thead><tbody><tr><td><a href="./simulated-annealing.html">模拟退火（SA）</a></td><td>单点邻域搜索、Metropolis 接受准则与降温表，易于实现</td></tr><tr><td><a href="./tabu-search.html">禁忌搜索（TS）</a></td><td>邻域搜索 + 禁忌表与渴望准则，抑制短循环、离开局部优</td></tr><tr><td><a href="./genetic-algorithm.html">遗传算法（GA）</a></td><td>种群、选择/交叉/变异，编码与适应度依赖问题</td></tr><tr><td><a href="./vns.html">变邻域搜索（VNS）</a></td><td>多邻域结构 + 抖动与局部搜索，系统性跳出局部最优</td></tr><tr><td><a href="./particle-swarm-optimization.html">粒子群优化（PSO）</a></td><td>惯性/认知/社会三项、pbest 与 gbest、分量/向量两式、参数与主循环</td></tr><tr><td><a href="./ant-colony-optimization.html">蚁群优化（ACO）</a></td><td>图上的信息素与随机成比例构造，正反馈 + 挥发，适于路径类组合问题</td></tr><tr><td><a href="./alns.html">自适应大邻域（ALNS）</a></td><td>多类破坏/修复算子、轮盘权重与段更新得分，大邻域上的自适应搜索</td></tr></tbody></table><p>其他元启发式篇目将随写作逐步补全。</p>',5)])])}const u=a(i,[["render",s]]);export{p as __pageData,u as default};
